import { RotatingLines } from "react-loader-spinner";

const Loading = () => {
  return (
    <div>
      <RotatingLines
        visible={true}
        height="80"
        width="80"
        ariaLabel="blocks-loading"
        wrapperStyle={{}}
        wrapperClass="blocks-wrapper"
        strokeColor="grey"
      />
      <div>
        Connecting
      </div>
    </div>
  );
};

export default Loading;
